import json
with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

changes = []
unchanged = []
for key in sorted(set(b.keys()) | set(a.keys())):
    bv = b.get(key)
    av = a.get(key)
    if bv == av:
        unchanged.append((key[0], key[1], bv))
    else:
        changes.append((key[0], key[1], bv, av))

print('=== CHANGES ===')
if not changes:
    print('None - conversion is fully version-neutral')
else:
    for c in changes:
        print(f'{c[0]} | {c[1]} | {c[2]} -> {c[3]}')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'{u[0]} | {u[1]} | {u[2]}')
"

